parameters.functionCode:
// Validate input data
const sessionId = $input.item.json.session_id;
if (!sessionId) {
  throw new Error('Missing session_id parameter');
}

return {
  json: {
    session_id: sessionId,
    event_type: $input.item.json.event_type || 'exam_completed',
    timestamp: new Date().toISOString()
  }
};

// Auto-score the exam based on answers and correct answers
const examData = $input.item.json;
const questions = examData.randomized_questions || [];
const answers = examData.answers || {};

let totalScore = 0;
let maxScore = 0;
const gradingDetails = [];

// Process each question
questions.forEach((question, index) => {
  const questionId = question.id || index;
  const userAnswer = answers[questionId];

  if (question.type === 'multiple_choice') {
    maxScore += question.score || 10;

    if (userAnswer && userAnswer === question.correct_answer) {
      totalScore += question.score || 10;
      gradingDetails.push({
        question_id: questionId,
        type: 'multiple_choice',
        correct: true,
        score: question.score || 10,
        max_score: question.score || 10
      });
    } else {
      gradingDetails.push({
        question_id: questionId,
        type: 'multiple_choice',
        correct: false,
        score: 0,
        max_score: question.score || 10,
        correct_answer: question.correct_answer,
        user_answer: userAnswer
      });
    }
  } else if (question.type === 'code' || question.type === 'coding') {
    maxScore += question.score || 20;

    // Simple code evaluation - check if answer exists and has some content
    let codeScore = 0;
    if (userAnswer && typeof userAnswer === 'string' && userAnswer.trim().length > 10) {
      // Basic scoring: give partial credit for attempt
      if (userAnswer.length > 50) {
        codeScore = Math.round((question.score || 20) * 0.7); // 70% for substantial attempt
      } else {
        codeScore = Math.round((question.score || 20) * 0.3); // 30% for basic attempt
      }
    }

    totalScore += codeScore;
    gradingDetails.push({
      question_id: questionId,
      type: 'code',
      score: codeScore,
      max_score: question.score || 20,
      user_answer: userAnswer,
      expected_answer: question.expected_output
    });
  }
});

const finalScore = maxScore > 0 ? Math.round((totalScore / maxScore) * 100) : 0;

return {
  json: {
    session_id: examData.session_id,
    candidate_id: examData.candidate_id,
    total_score: totalScore,
    max_score: maxScore,
    percentage_score: finalScore,
    grading_details: gradingDetails,
    questions_count: questions.length,
    timestamp: new Date().toISOString()
  }
};

// Analyze proctoring events and calculate cheating probability
const examData = $input.item.json;
const proctoringLogs = examData.proctoring_logs || [];

// Define event weights for cheating probability
const eventWeights = {
  'face_lost': 0.3,
  'multiple_faces': 0.8,
  'phone_detected': 0.9,
  'tab_switch': 0.7,
  'fullscreen_exit': 0.6,
  'suspicious_movement': 0.4,
  'poor_lighting': 0.2
};

let cheatingScore = 0;
let totalEvents = 0;
const suspiciousEvents = [];

// Process each proctoring event
proctoringLogs.forEach(log => {
  const eventType = log.event_type;
  const confidence = log.confidence || 0.7;
  const weight = eventWeights[eventType] || 0.3;

  totalEvents++;
  const eventScore = weight * confidence;
  cheatingScore += eventScore;

  if (eventScore > 0.5) {
    suspiciousEvents.push({
      timestamp: log.timestamp,
      event_type: eventType,
      confidence: confidence,
      severity: eventScore > 0.7 ? 'high' : eventScore > 0.4 ? 'medium' : 'low',
      description: getEventDescription(eventType),
      duration: log.event_metadata?.duration || '1 วินาที'
    });
  }
});

// Normalize cheating probability (0-100%)
const cheatingProbability = Math.min(100, Math.round(cheatingScore * 25));

// Determine AI confidence based on data quality
let aiConfidence = 85; // Base confidence
if (totalEvents > 10) aiConfidence += 10;
if (proctoringLogs.length > 5) aiConfidence += 5;
aiConfidence = Math.min(95, aiConfidence);

// Determine pass/fail status
const passingScore = 60;
const examPassed = examData.percentage_score >= passingScore && cheatingProbability < 50;

function getEventDescription(eventType) {
  const descriptions = {
    'face_lost': 'ไม่พบใบหน้าในกรอบ',
    'multiple_faces': 'พบใบหน้ามากกว่า 1 คน',
    'phone_detected': 'พบวัตถุคล้ายมือถือ',
    'tab_switch': 'เปลี่ยนแท็บเบราว์เซอร์',
    'fullscreen_exit': 'ออกจากโหมดเต็มจอ',
    'suspicious_movement': 'ความเคลื่อนไหวน่าสงสัย',
    'poor_lighting': 'แสงไม่เพียงพอ'
  };
  return descriptions[eventType] || 'กิจกรรมน่าสงสัย';
}

return {
  json: {
    session_id: examData.session_id,
    candidate_id: examData.candidate_id,
    exam_score: examData.percentage_score,
    cheating_percentage: cheatingProbability,
    ai_confidence: aiConfidence,
    status: examPassed ? 'passed' : 'failed',
    total_events: totalEvents,
    suspicious_events: suspiciousEvents,
    analysis_metadata: {
      total_proctoring_events: proctoringLogs.length,
      high_risk_events: suspiciousEvents.filter(e => e.severity === 'high').length,
      passing_threshold: passingScore,
      cheating_threshold: 50,
      analysis_timestamp: new Date().toISOString()
    }
  }
};

