// Generate comprehensive evaluation report
const data = $input.item.json;

const report = {
  success: true,
  message: 'Exam evaluation completed successfully',
  session_id: data.session_id,
  candidate_id: data.candidate_id,
  results: {
    score: data.exam_score,
    status: data.status,
    cheating_probability: data.cheating_percentage,
    ai_confidence: data.ai_confidence,
    risk_level: data.cheating_percentage >= 70 ? 'high' : data.cheating_percentage >= 30 ? 'medium' : 'low'
  },
  proctoring_summary: {
    total_events: data.total_events,
    suspicious_events_count: data.suspicious_events.length,
    high_severity_events: data.suspicious_events.filter(e => e.severity === 'high').length
  },
  processing_metadata: {
    workflow_version: 'exam_completion_v1',
    processing_time: new Date().toISOString(),
    components_processed: ['scoring', 'proctoring_analysis', 'risk_assessment']
  }
};

return { json: report };
